function greetUser(name, title) {
  // 'title' is undefined if not supplied
  const prefix = title ? `${title} ` : '';
  return `Welcome, ${prefix}${name}!`;
}

console.log(greetUser('Alice'));           // Welcome, Alice!
console.log(greetUser('Bob', 'Dr.'));      // Welcome, Dr. Bob!

// Objects — reference is passed, so mutations affect the original
function addScore(user, points) {
  user.score += points; // mutates the ORIGINAL object
}

const student = { name: 'Carol', score: 80 };
addScore(student, 10);
console.log(student.score); // 90

