  // 'arguments' captures everything — no named params needed
  console.log(arguments[0]); // 'a'
  console.log(arguments.length); // 3
  // arguments.forEach(...)  — not a real Array
  Array.from(arguments).forEach(arg => console.log(arg)); // 
}

